We may refactor this method as follows:

```python
def to_representation(self, value):
    """
    Range instances -> dicts of primitive datatypes.
    """
    if isinstance(value, dict) and not value:
        return value
    elif value.isempty:
        return {"empty": True}

    lower = value.get("lower") if isinstance(value, dict) else value.lower
    upper = value.get("upper") if isinstance(value, dict) else value.upper
    bounds = value.get("bounds") if isinstance(value, dict) else value._bounds

    return {"lower":  self.child.to_representation(lower) if lower is not None else None,
            "upper": self.child.to_representation(upper) if upper is not None else None,
            "bounds": bounds}
```

or 

```python
def to_representation(self, value):
    """
    Range instances -> dicts of primitive datatypes.
    """
    if isinstance(value, dict):
        if not value:
            return value

        lower = value.get("lower")
        upper = value.get("upper")
        bounds = value.get("bounds")
    else:
        if value.isempty:
            return {"empty": True}
        
        lower = value.lower
        upper = value.upper
        bounds = value._bounds

    return {"lower":  self.child.to_representation(lower) if lower is not None else None,
            "upper": self.child.to_representation(upper) if upper is not None else None,
            "bounds": bounds}
```

