```scala
    // Assume the schema for df is userCol, timeCol, col1, ..., coln, col1', ... coln'
    // We need to generate hist_seq for col1, ..., coln, but not col1', ..., coln'
    // genHistwill return a new field "friesian_history" whose schema is:
    // Array[Struct<userCol, timeCol, col1, ..., coln, col1', ..., coln', col1_hist_seq, ..., coln_hist_seq>]
    val genHist = udf(f = (his_collect: Seq[Row]) => {
      val full_rows = his_collect.sortBy(x => x.getAs[Long](sortCol)).toArray
      val n = full_rows.length
      val result: Seq[Row] = (minLength - 1 to n - 1).map(i => {
        val lowerBound = ...
        val row = full_rows(i)
        val seq = colIndex.map(c =>         //colIndex is the position index for colNames
          full_rows.slice(lowerBound, i).map(r => r.get(c)))
        Row.fromSeq(row.toSeq ++ seq)
      })
      result
    }, schema)

